using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ──────────────────────────────────────────────────────────
// 1. Get strongly-typed JsonTypeInfo<T> via the generic method
// ──────────────────────────────────────────────────────────
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind = {personInfo.Kind}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"  Serialized: {json}");

// ──────────────────────────────────────────────────────────
// 2. Probe without throwing using TryGetTypeInfo
// ──────────────────────────────────────────────────────────

// Case A: type IS resolvable
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? resolved))
{
    var typed = (JsonTypeInfo<Person>)resolved;
    Console.WriteLine($"\nTryGetTypeInfo(Person) succeeded — Kind = {typed.Kind}");
}
else
{
    Console.WriteLine("\nTryGetTypeInfo(Person) returned false (unexpected)");
}

// Case B: type is NOT resolvable (empty resolver → no metadata)
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // empty composite → resolves nothing
};

if (restrictedOptions.TryGetTypeInfo(typeof(Person), out _))
{
    Console.WriteLine("TryGetTypeInfo(Person) on restricted options: found (unexpected)");
}
else
{
    Console.WriteLine("TryGetTypeInfo(Person) on restricted options: not found — no exception!");
}

